let cachedLogoBase64: string | null = null;

function getLogoBase64(): string | null {
  if (cachedLogoBase64 !== null) return cachedLogoBase64;
  try {
    const logoPath = path.resolve(process.cwd(), 'attached_assets', 'T-Bank_White_No_Padding_1772137291638_1772736520402.png');
    const logoBytes = fs.readFileSync(logoPath);
    cachedLogoBase64 = logoBytes.toString('base64');
    return cachedLogoBase64;
  } catch {
    cachedLogoBase64 = '';
    return null;
  }
}

function drawDocHeader(doc: jsPDF, title: string, logoAlias?: string): number {
  const headerH = 18;
  doc.setFillColor(COLORS.headerBg);
  doc.rect(0, 0, PAGE_W, headerH, 'F');

  const logo = getLogoBase64();
  if (logo) {
    const logoAspect = 3.5;
    const logoH = 11;
    const logoW = logoH * logoAspect;
    if (logoAlias) {
      doc.addImage(`data:image/png;base64,${logo}`, 'PNG', MARGIN.left, (headerH - logoH) / 2, logoW, logoH, logoAlias, 'FAST');
    } else {
      doc.addImage(`data:image/png;base64,${logo}`, 'PNG', MARGIN.left, (headerH - logoH) / 2, logoW, logoH, 'tbank_logo', 'FAST');
    }
  }

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(16);
  doc.setTextColor(COLORS.white);
  const titleW = doc.getTextWidth(title);
  doc.text(title, PAGE_W - MARGIN.right - titleW, headerH / 2 + 2);

  return headerH + 8;
}

function drawPageTitle(doc: jsPDF, text: string, y: number): number {
  y += 2;
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(14);
  doc.setTextColor(COLORS.sectionLine);
  doc.text(text, MARGIN.left, y);
  return y + SECTION_GAP;
}

