  doc.setLineWidth(0.3);
  doc.line(MARGIN.left, y - 1, PAGE_W - MARGIN.right, y - 1);
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(SUB_HEADER_SIZE);
  doc.setTextColor(COLORS.mediumGray);
  doc.text(text, MARGIN.left, y + 4);
  return y + SUB_GAP;
}

function drawLabel(doc: jsPDF, text: string, x: number, y: number, required = false): void {
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(LABEL_SIZE);
  doc.setTextColor(COLORS.lightGray);
  const lines = text.split('\n');
  for (let i = 0; i < lines.length; i++) {
    doc.text(lines[i], x, y + i * 3.5);
  }
  if (required) {
    const lastLine = lines[lines.length - 1];
    const tw = doc.getTextWidth(lastLine);
    doc.setTextColor('#c0392b');
    doc.text(' *', x + tw, y + (lines.length - 1) * 3.5);
  }
}

function drawUnderline(doc: jsPDF, x: number, y: number, width: number): void {
  doc.setDrawColor(COLORS.borderGray);
  doc.setLineWidth(0.3);
  doc.line(x, y, x + width, y);
}

function addTextField(doc: jsPDF, name: string, x: number, underlineY: number, width: number, value: string, height = FIELD_H): void {
  const f = new (doc as any).AcroFormTextField();
  f.fieldName = name;
  f.x = x;
  f.y = underlineY - height;
  f.width = width;
  f.height = height;
  f.fontSize = 0;
  f.fontName = 'Helvetica';
  f.defaultValue = value;
  f.value = value;
  f.textAlign = 'left';
  doc.addField(f);
}

function addTextArea(doc: jsPDF, name: string, x: number, y: number, width: number, height: number, value: string): void {
  doc.setDrawColor(COLORS.borderGray);
  doc.setLineWidth(0.3);
  doc.rect(x, y, width, height);

  const f = new (doc as any).AcroFormTextField();
  f.fieldName = name;
  f.x = x;
  f.y = y;
  f.width = width;
  f.height = height;
  f.fontSize = 0;
  f.fontName = 'Helvetica';
  f.multiline = true;
  f.defaultValue = value;
  f.value = value;
  f.textAlign = 'left';
  doc.addField(f);
}

function addCheckBox(doc: jsPDF, name: string, x: number, y: number, size: number, checked = false): void {
  const f = new (doc as any).AcroFormCheckBox();
  f.fieldName = name;
  f.x = x;
  f.y = y;
  f.width = size;
  f.height = size;
  f.maxFontSize = Math.round(size * 2.835 * 0.5);
  if (checked) {
    f.value = 'On';
    f.defaultValue = 'On';
    f.appearanceState = 'On';
  } else {
    f.value = 'Off';
    f.defaultValue = 'Off';
    f.appearanceState = 'Off';
  }
  doc.addField(f);
}

function addComboBox(doc: jsPDF, name: string, x: number, underlineY: number, width: number, options: string[], value: string): void {
  const f = new (doc as any).AcroFormComboBox();
  f.fieldName = name;
  f.x = x;
  f.y = underlineY - FIELD_H;
  f.width = width;
  f.height = FIELD_H;
  f.fontSize = FIELD_FONT_SIZE;
  f.fontName = 'Helvetica';
  f.setOptions(options);
