    f.defaultValue = value;
  }
  doc.addField(f);
}

function addYesNoRadio(doc: jsPDF, name: string, x: number, y: number, value: string): void {
  const cbSize = 4;
  const lowerVal = (value || '').toLowerCase();
  const isYes = lowerVal === 'yes';
  const isNo = lowerVal === 'no';

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(LABEL_SIZE);
  doc.setTextColor(COLORS.darkGray);

  doc.text('Yes', x, y + 3);
  const yesTextW = doc.getTextWidth('Yes');
  addCheckBox(doc, `${name}_yes`, x + yesTextW + 1.5, y - 0.5, cbSize, isYes);

  const noX = x + yesTextW + cbSize + 6;
  doc.text('No', noX, y + 3);
  const noTextW = doc.getTextWidth('No');
  addCheckBox(doc, `${name}_no`, noX + noTextW + 1.5, y - 0.5, cbSize, isNo);
}

interface FieldConfig {
  label: string;
  fieldName: string;
  value: string;
  required?: boolean;
  type?: 'text' | 'combo' | 'dropdown';
  options?: string[];
}

function drawFieldRow(doc: jsPDF, fields: FieldConfig[], y: number, colWidths?: number[], colGap = 8): number {
  const n = fields.length;
  let widths: number[];
  let xs: number[];

  if (colWidths) {
    widths = colWidths;
    xs = [];
    let cx = MARGIN.left;
    for (let i = 0; i < n; i++) {
      xs.push(cx);
      cx += widths[i] + colGap;
    }
  } else if (n === 1) {
    widths = [CONTENT_W];
    xs = [MARGIN.left];
  } else if (n === 2) {
    widths = [col2W, col2W];
    xs = [col2X(0), col2X(1)];
  } else if (n === 3) {
    widths = [col3W, col3W, col3W];
    xs = [col3X(0), col3X(1), col3X(2)];
  } else if (n === 4) {
    widths = [col4W, col4W, col4W, col4W];
    xs = [col4X(0), col4X(1), col4X(2), col4X(3)];
  } else {
    widths = Array(n).fill(col5W);
    xs = Array.from({ length: n }, (_, i) => col5X(i));
  }

  for (let i = 0; i < n; i++) {
    const f = fields[i];
    if (f.label) {
      drawLabel(doc, f.label, xs[i], y, f.required);
    }
  }

  const underlineY = y + LABEL_FIELD_GAP + FIELD_H;

  for (let i = 0; i < n; i++) {
    const f = fields[i];
    drawUnderline(doc, xs[i], underlineY, widths[i]);
    if (f.type === 'combo' || f.type === 'dropdown') {
      addComboBox(doc, f.fieldName, xs[i], underlineY, widths[i], f.options || [], f.value);
    } else {
      addTextField(doc, f.fieldName, xs[i], underlineY, widths[i], f.value);
    }
  }

  return underlineY;
}

