function drawRichText(doc: jsPDF, text: string, x: number, y: number, maxWidth: number, lineH: number, fontSize = LABEL_SIZE): number {
  const parts = text.split(/(<b>.*?<\/b>)/g);
  const segments: { text: string; bold: boolean }[] = [];
  for (const part of parts) {
    const match = part.match(/^<b>(.*)<\/b>$/);
    if (match) {
      segments.push({ text: match[1], bold: true });
    } else if (part) {
      segments.push({ text: part, bold: false });
    }
  }

  const words: { word: string; bold: boolean }[] = [];
  for (const seg of segments) {
    const ws = seg.text.split(' ');
    for (const w of ws) {
      if (w) words.push({ word: w, bold: seg.bold });
    }
  }

  let cx = x;
  let cy = y;

  for (let wi = 0; wi < words.length; wi++) {
    const w = words[wi];
    doc.setFont('helvetica', w.bold ? 'bold' : 'normal');
    doc.setFontSize(fontSize);
    const ww = doc.getTextWidth(w.word);
    const spaceW = doc.getTextWidth(' ');

    if (cx + ww > x + maxWidth && cx > x) {
      cy += lineH;
      cx = x;
    }

    doc.text(w.word, cx, cy);
    cx += ww + spaceW;
  }

  return cy + lineH;
}

function drawInfoBox(doc: jsPDF, paragraphs: string[], y: number): number {
  const lineH = 4.5;
  const pad = 4;

  let totalH = pad + 3;
  const wrappedParas: string[][] = [];
  const innerW = CONTENT_W - pad * 2;
  let nonEmptyCount = 0;

  for (const para of paragraphs) {
    if (!para) {
      wrappedParas.push([]);
      totalH += lineH * 0.5;
      continue;
    }
    const plainText = para.replace(/<b>|<\/b>/g, '');
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(INFO_BOX_SIZE);
    const lines = doc.splitTextToSize(plainText, innerW);
    wrappedParas.push(lines);
    totalH += lines.length * lineH + 1;
    nonEmptyCount++;
  }
  totalH += pad;

  doc.setFillColor(COLORS.infoBgR, COLORS.infoBgG, COLORS.infoBgB);
  doc.roundedRect(MARGIN.left, y, CONTENT_W, totalH, 1.5, 1.5, 'F');
  doc.setDrawColor(COLORS.infoBorder);
  doc.setLineWidth(0.8);
  doc.line(MARGIN.left, y, MARGIN.left, y + totalH);

  let textY = y + pad + 3;
  for (let pi = 0; pi < paragraphs.length; pi++) {
    if (!paragraphs[pi]) {
      textY += lineH * 0.5;
      continue;
    }
    doc.setTextColor(COLORS.mediumGray);
    textY = drawRichText(doc, paragraphs[pi], MARGIN.left + pad, textY, innerW, lineH, INFO_BOX_SIZE);
    textY += 1;
  }

  return y + totalH + 2;
}

