  y = drawPageTitle(doc, 'Business Applicant Information', y);

  y = drawInfoBox(doc, [
    'In this section, enter information about the <b>business that is applying for this SBA loan</b>. This is the company that will borrow the funds, sign the loan documents, and be responsible for repayment. If the borrowing company has not been formed yet, check <b>"Entity to be Formed."</b>',
    '',
    'The <b>business address</b> is the physical street address where your business operates. This should be your main operating location\u2014not a P.O. Box. The <b>project address</b> is the physical address of the project being financed\u2014such as a new location, renovation site, construction project, or the property being purchased. You only need to complete this section if the project address is different from your main business address.',
  ], y);

  y += FIELD_SPACING * 0.75;

  addCheckBox(doc, 'ba_entityToBeFormed', MARGIN.left, y, CHECKBOX_SIZE, !!ba.entityToBeFormed);
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(FIELD_FONT_SIZE);
  doc.setTextColor(COLORS.darkGray);
  doc.text('Entity to be Formed (Check if the business has not yet been formed)', MARGIN.left + CHECKBOX_SIZE + 3, y + 3);
  y += 10 + FIELD_SPACING * 0.75;

  y = drawSectionHeader(doc, 'Entity Details', y);

  y = drawFieldRow(doc, [
    { label: 'Legal Business Name', fieldName: 'ba_legalName', value: str(ba.legalName) },
    { label: 'DBA or Trade Name', fieldName: 'ba_dba', value: str(ba.dba) },
  ], y);
  y += FIELD_SPACING;

  const entityTypeDisplayMap: Record<string, string> = {
    'cooperative': 'Cooperative',
    'corporation': 'Corporation',
    'llc': 'Limited Liability Company (LLC)',
    'llp': 'Limited Liability Partnership',
    'partnership': 'Partnership',
    'sole-proprietor': 'Sole Proprietorship',
    's-corp': 'Subchapter S Corporation',
    'trust': 'Trust',
  };

  const entityTypeDisplay = entityTypeDisplayMap[ba.entityType] || str(ba.entityType);
  y = drawFieldRow(doc, [
    { label: 'Entity Type', fieldName: 'ba_entityType', value: entityTypeDisplay, type: 'combo',
      options: ['', 'Cooperative', 'Corporation', 'Limited Liability Company (LLC)', 'Limited Liability Partnership', 'Partnership', 'Sole Proprietorship', 'Subchapter S Corporation', 'Trust'] },
    { label: 'Business TIN (EIN/SSN)', fieldName: 'ba_ein', value: str(ba.ein) },
  ], y);
  y += FIELD_SPACING;

  y = drawFieldRow(doc, [
    { label: 'Business Website Address', fieldName: 'ba_website', value: str(ba.website) },
  ], y);
  y += FIELD_SPACING + 2;

  y = drawSectionHeader(doc, 'Business Address', y);

  y = drawFieldRow(doc, [
    { label: 'Street', fieldName: 'ba_businessStreet', value: str(addr.street) },
  ], y);
  y += FIELD_SPACING;

  y = drawFieldRow(doc, [
    { label: 'City', fieldName: 'ba_businessCity', value: str(addr.city) },
    { label: 'State', fieldName: 'ba_businessState', value: str(addr.state) },
    { label: 'ZIP Code', fieldName: 'ba_businessZip', value: str(addr.zip) },
  ], y);
  y += FIELD_SPACING + 2;

  y = drawSectionHeader(doc, 'Project Address', y);

  y = drawFieldRow(doc, [
    { label: 'Street', fieldName: 'ba_projectStreet', value: str(paddr.street) },
  ], y);
  y += FIELD_SPACING;

  y = drawFieldRow(doc, [
    { label: 'City', fieldName: 'ba_projectCity', value: str(paddr.city) },
    { label: 'State', fieldName: 'ba_projectState', value: str(paddr.state) },
    { label: 'ZIP Code', fieldName: 'ba_projectZip', value: str(paddr.zip) },
  ], y);
  y += FIELD_SPACING + 2;

  drawFooter(doc, footerText);
  doc.addPage();
  y = drawDocHeader(doc, 'Business Applicant Form');

  y = drawPageTitle(doc, 'Business Applicant Ownership', y);

  y = drawInfoBox(doc, [
    'SBA requires information on all natural persons (real human beings) who own 20% or more of the applicant business. This includes both direct ownership (owning shares in the business directly) and indirect ownership (owning shares through another entity like an LLC, corporation, or trust).',
    '',
    'In the table below, list every individual who holds an ownership interest \u2014 directly or indirectly \u2014 in the borrowing entity. Ownership percentages must total 100%. Ensure names match official identification and legal documents exactly. In the case of indirect ownership, explain the relationship between the individual owner and the entity through which they own an interest in the business applicant.',
    '',
    '<b>Note:</b> If there are more owners than available rows, add those details to the box at the bottom of the page.',
  ], y);

  y += FIELD_SPACING * 0.75;

  for (let r = 0; r < 5; r++) {
    const app = applicants[r] || {};
    if (needNewPage(y, FIELD_SPACING)) {
      drawFooter(doc, footerText);
      doc.addPage();
      y = drawDocHeader(doc, 'Business Applicant Form');
    }
    const ownerColWidths = [28, 28, 10, 32, 43, 36];
    if (r === 0) {
      const colGapH = 3;
      const col0X = MARGIN.left;
      const col1X = col0X + ownerColWidths[0] + colGapH;
      const col2X = col1X + ownerColWidths[1] + colGapH;
      const col3X = col2X + ownerColWidths[2] + colGapH;
      const col4X = col3X + ownerColWidths[3] + colGapH;
      const col5X = col4X + ownerColWidths[4] + colGapH;
      drawLabel(doc, 'First Name', col0X, y + 3.5);
      drawLabel(doc, 'Last Name', col1X, y + 3.5);
      drawLabel(doc, 'Own %', col2X, y + 3.5);
      drawLabel(doc, 'Direct /', col3X, y);
      drawLabel(doc, 'Indirect', col3X, y + 3.5);
      drawLabel(doc, 'Project Role', col4X, y + 3.5);
      drawLabel(doc, 'Role in', col5X, y);
      drawLabel(doc, 'Business Ops', col5X, y + 3.5);
      const headerLineY = y + 3.5 + LABEL_FIELD_GAP;
      doc.setDrawColor(COLORS.borderGray);
      doc.setLineWidth(0.3);
      const colGap = 3;
      let cx = MARGIN.left;
      for (const cw of ownerColWidths) {
        doc.line(cx, headerLineY, cx + cw, headerLineY);
        cx += cw + colGap;
      }
      y += LABEL_FIELD_GAP + 5;
    }
    y = drawFieldRow(doc, [
      { label: '', fieldName: `ba_own${r}_firstName`, value: str(app.firstName) },
      { label: '', fieldName: `ba_own${r}_lastName`, value: str(app.lastName) },
      { label: '', fieldName: `ba_own${r}_ownershipPct`, value: app.ownershipPercentage ? `${app.ownershipPercentage}` : '' },
      { label: '', fieldName: `ba_own${r}_ownershipType`, value: ownershipTypeDisplayMap[app.ownershipType] || str(app.ownershipType), type: 'combo',
        options: ['', ...Object.values(ownershipTypeDisplayMap)] },
      { label: '', fieldName: `ba_own${r}_projectRole`, value: projectRoleDisplayMap[app.projectRole] || str(app.projectRole), type: 'combo',
        options: ['', ...Object.values(projectRoleDisplayMap)] },
      { label: '', fieldName: `ba_own${r}_businessRole`, value: businessRoleDisplayMap[app.businessRole] || str(app.businessRole), type: 'combo',
        options: ['', ...Object.values(businessRoleDisplayMap)] },
    ], y, ownerColWidths, 3);
    y += Math.round((FIELD_H + 6) * 0.15);
  }

  y += FIELD_SPACING;

  drawLabel(doc, 'Other Owners / Description of Indirect Ownership', MARGIN.left, y);
  y += 3;
  addTextArea(doc, 'ba_otherOwners', MARGIN.left, y, CONTENT_W, MULTILINE_H, str(ba.otherOwners));
  y += MULTILINE_H + 3;

  drawFooter(doc, footerText);
  doc.addPage();
  y = drawDocHeader(doc, 'Business Applicant Form');

  y = drawPageTitle(doc, 'SBA Eligibility', y);

  const sbaQuestions: Array<{ key: string; label: string; hintText?: string }> = [
    { key: 'convicted', label: 'Have any of the applicants ever been convicted of a criminal offense?', hintText: 'Whether any owner or individual applicant has been found guilty of a misdemeanor or felony in a court of law. Minor traffic violations (speeding, parking) do not count. The SBA evaluates past criminal history to determine eligibility for federal financing and to comply with federal background-screening requirements. A conviction does not automatically disqualify an applicant\u2014SBA simply needs accurate disclosure.' },
    { key: 'arrested', label: 'Are any of the applicants currently subject to an indictment, criminal information, arraignment, or other means of formal criminal charge?', hintText: 'Whether any applicant is presently facing formal criminal charges, awaiting trial, or has an unresolved indictment or legal accusation. Federal rules prohibit the SBA from approving a loan when an applicant is currently charged with a crime. This disclosure ensures legal compliance and prevents delays in processing the loan.' },
    { key: 'pendingLawsuits', label: 'Are any of the applicants parties to any pending lawsuits?', hintText: 'Whether any applicant is involved in an active civil lawsuit\u2014either as a plaintiff (bringing the suit) or as a defendant (being sued). Pending litigation can affect the financial stability of the borrower. The SBA and the lender must assess whether the lawsuit could impact the applicant\'s ability to repay the loan.' },
    { key: 'childSupport', label: 'Are any of the applicants currently delinquent on any child support obligations?', hintText: 'Whether any applicant is behind on court-ordered child support payments by more than 60 days. Federal law requires the SBA to verify that applicants with more than 60 days of unpaid child support are not eligible for SBA assistance. This protects federal program integrity and ensures compliance with federal debt policies.' },
    { key: 'taxLiens', label: 'Are any of the applicants subject to any tax liens?', hintText: 'Whether any applicant currently has federal, state, or local tax authorities placing a lien on their assets due to unpaid taxes. Outstanding tax liens may affect borrower eligibility and repayment ability. The SBA requires full disclosure so lenders can evaluate financial risk and determine whether tax obligations must be resolved before loan approval.' },
    { key: 'bankruptcy', label: 'Have any of the applicants ever been involved in a bankruptcy proceeding?', hintText: 'Whether any applicant has filed for or been involved in personal or business bankruptcy, including Chapter 7, 11, or 13, and whether the bankruptcy has been discharged or is still active. Bankruptcy does not automatically disqualify an applicant, but it must be reviewed to assess repayment ability and creditworthiness.' },
    { key: 'federalDebt', label: 'Are any of the applicants delinquent on any federal debt?', hintText: 'Whether any applicant is behind on payments owed to a federal agency. Examples include: SBA loans, FHA or VA loans, federally guaranteed student loans, federal tax debt, or any other debt owed to the U.S. government. Federal law prohibits approving SBA loans when an applicant is delinquent on federal debt. SBA uses this information to determine eligibility and prevent conflicts with other government credit programs.' },
    { key: 'nonCitizenOwner', label: 'Do any direct or indirect owners of the applicant business lack U.S. Citizenship or U.S. National status, or maintain their principal residence outside the United States, its territories, or possessions?' },
  ];

  const radioAreaW = 32;
  const questionTextW = CONTENT_W - radioAreaW;
  const radioX = MARGIN.left + questionTextW + 4;
  const hintLineH = 3.2;

  for (let qi = 0; qi < sbaQuestions.length; qi++) {
    const q = sbaQuestions[qi];

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(LABEL_SIZE);
    const qText = `${qi + 1}. ${q.label}`;
    const lines = doc.splitTextToSize(qText, questionTextW);
    let estimatedHeight = lines.length * 4 + 5;
    if (q.hintText) {
      doc.setFont('helvetica', 'italic');
      doc.setFontSize(7.5);
      const hintLinesEst = doc.splitTextToSize(q.hintText, questionTextW);
      estimatedHeight += 1 + hintLinesEst.length * hintLineH + 4;
    }
    if (needNewPage(y, estimatedHeight)) {
      drawFooter(doc, footerText);
      doc.addPage();
      y = drawDocHeader(doc, 'Business Applicant Form');
    }

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(LABEL_SIZE);
    doc.setTextColor(COLORS.darkGray);
    const questionY = y;
    for (const line of lines) {
      doc.text(line, MARGIN.left, y);
      y += 4;
    }

    const val = str((sba as any)[q.key]);
    addYesNoRadio(doc, `sba_${q.key}`, radioX, questionY - 3, val);

    if (q.hintText) {
      y += 1;
      doc.setFont('helvetica', 'italic');
      doc.setFontSize(7.5);
      doc.setTextColor(107, 114, 128);
      const hintLines = doc.splitTextToSize(q.hintText, questionTextW);
      for (const hLine of hintLines) {
        doc.text(hLine, MARGIN.left, y);
        y += hintLineH;
      }
      y += 4;
    } else {
      y += 1;
      y += 4;
    }
  }

  if (needNewPage(y, MULTILINE_H + 6)) {
    drawFooter(doc, footerText);
    doc.addPage();
    y = drawDocHeader(doc, 'Business Applicant Form');
  }

  drawLabel(doc, 'If you answered yes to any of these questions, please explain here.', MARGIN.left, y);
  y += 3;
  addTextArea(doc, 'sba_eligibilityExplanation', MARGIN.left, y, CONTENT_W, MULTILINE_H, str(sba?.eligibilityExplanation));
  y += MULTILINE_H + 3;

  drawFooter(doc, footerText);
}

function drawIndividualInstructionsPages(doc: jsPDF, footerText: string): void {
  doc.addPage();
  let y = drawDocHeader(doc, 'Individual Applicant');

  const S = 7;
  const LH = 3.2;
  const SH = 8.5;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(11);
  doc.setTextColor(COLORS.sectionLine);
  doc.text('Instructions for Borrowers', MARGIN.left, y);
  y += 6;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(SH);
  doc.setTextColor(COLORS.sectionLine);
  doc.text('What Is This Form?', MARGIN.left, y);
  doc.setDrawColor(COLORS.sectionLine);
  doc.setLineWidth(0.4);
  doc.line(MARGIN.left, y + 1.5, PAGE_W - MARGIN.right, y + 1.5);
  y += 4.5;

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(S);
  doc.setTextColor(COLORS.mediumGray);
  const whatIsLines = doc.splitTextToSize(
    'This Individual Applicant Form is part of your SBA loan application with T Bank. It collects personal, financial, and professional information about each individual connected to the loan. This helps us understand who is involved in the business, their ownership role, and their qualifications, all of which the SBA requires as part of the application review.',
    CONTENT_W
  );
  for (const line of whatIsLines) {
    doc.text(line, MARGIN.left, y);
    y += LH;
  }
  y += 1.5;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(SH);
  doc.setTextColor(COLORS.sectionLine);
  doc.text('Who Needs to Complete This Form?', MARGIN.left, y);
  doc.setDrawColor(COLORS.sectionLine);
  doc.setLineWidth(0.4);
  doc.line(MARGIN.left, y + 1.5, PAGE_W - MARGIN.right, y + 1.5);
  y += 4.5;

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(S);
  doc.setTextColor(COLORS.mediumGray);
  doc.text('A separate form must be completed for each of the following:', MARGIN.left, y);
  y += LH + 1;

  const whoNeeds = [
    'Every owner with 20% or more equity in the business',
    'All general partners and managing members of an LLC',
    'Any individual who will be personally guaranteeing the loan',
  ];
  for (const item of whoNeeds) {
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(S);
    doc.setTextColor(COLORS.mediumGray);
    doc.text('\u2022', MARGIN.left + 3, y);
    doc.text(item, MARGIN.left + 7, y);
    y += LH + 0.5;
  }
  y += 2;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(SH);
  doc.setTextColor(COLORS.sectionLine);
  doc.text('Section-by-Section Guide', MARGIN.left, y);
  doc.setDrawColor(COLORS.sectionLine);
  doc.setLineWidth(0.4);
  doc.line(MARGIN.left, y + 1.5, PAGE_W - MARGIN.right, y + 1.5);
  y += 5;

  const sectionItems: { title: string; text: string }[] = [
    { title: 'Personal Information', text: 'Provide your legal name exactly as it appears on your government-issued ID.' },
    { title: 'Credit Profile', text: 'Select your estimated credit score range. Use the explanation box if your score was impacted by a specific event.' },
    { title: 'Project & Business Involvement', text: 'Project Role, Ownership %, Ownership Type, Role in Operations, Travel Time, Experience, and more.' },
    { title: 'Other Owned Businesses', text: 'Disclose all business affiliations for you and any owner with 20%+ equity, including entity drill-downs.' },
  ];

  for (const item of sectionItems) {
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(S);
    doc.setTextColor(COLORS.darkGray);
    const titleText = `${item.title}: `;
    doc.text(titleText, MARGIN.left, y);
    const tw = doc.getTextWidth(titleText);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(COLORS.mediumGray);
    const descLines = doc.splitTextToSize(item.text, CONTENT_W - tw);
    if (descLines.length <= 1) {
      doc.text(descLines[0] || '', MARGIN.left + tw, y);
      y += LH + 0.8;
    } else {
      const combined = `${item.title}: ${item.text}`;
      const wLines = doc.splitTextToSize(combined, CONTENT_W);
      y -= LH;
      for (const wl of wLines) {
        y += LH;
        doc.text(wl, MARGIN.left, y);
      }
      y += LH + 0.8;
    }
  }
  y += 1;

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(9);
  doc.setTextColor(COLORS.sectionLine);
  doc.text('Understanding Indirect Ownership', MARGIN.left, y);
  y += 1;
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(6.5);
  doc.setTextColor(COLORS.lightGray);
  doc.text('SBA requires disclosure of all natural persons who own 20% or more \u2014 including those who own through other entities.', MARGIN.left, y + 3);
  y += 7;

  const leftColW = CONTENT_W * 0.48;
  const rightColX = MARGIN.left + CONTENT_W * 0.52;
  const rightColW = CONTENT_W * 0.48;
  const diagramStartY = y;

  doc.setFillColor(245, 247, 250);
  doc.setDrawColor(COLORS.borderGray);
  doc.setLineWidth(0.3);
  doc.roundedRect(MARGIN.left, y, leftColW, 2, 1, 1, 'F');

  doc.setFont('helvetica', 'bold');
  doc.setFontSize(6.5);
  doc.setTextColor(COLORS.lightGray);
  doc.text('EXAMPLE: ABC RESTAURANT LLC', MARGIN.left + 2, y + 3);
  y += 5;

  const boxH = 10;
  const boxGap = 3;
  const headerBoxW = leftColW - 8;
  const headerBoxX = MARGIN.left + 4;

  doc.setFillColor(COLORS.headerBg);
  doc.roundedRect(headerBoxX, y, headerBoxW, boxH, 1.5, 1.5, 'F');
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(7);
  doc.setTextColor(COLORS.white);
  const abcText = 'ABC Restaurant LLC';
  const abcW = doc.getTextWidth(abcText);
  doc.text(abcText, headerBoxX + (headerBoxW - abcW) / 2, y + 4.5);
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(5.5);
  const abcSubText = 'Applicant Business';
  const abcSubW = doc.getTextWidth(abcSubText);
  doc.text(abcSubText, headerBoxX + (headerBoxW - abcSubW) / 2, y + 8);
  y += boxH + boxGap;

  const halfBoxW = (headerBoxW - boxGap) / 2;

  const CORP_NATURAL = '#74899e';
  const CORP_ENTITY = '#3d6a88';
  const CORP_BRIGHT = '#00a3e0';

  doc.setFillColor(COLORS.white);
  doc.setDrawColor(CORP_NATURAL);
  doc.setLineWidth(0.8);
  doc.roundedRect(headerBoxX, y, halfBoxW, boxH + 3, 1.5, 1.5, 'FD');
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(6.5);
  doc.setTextColor(COLORS.darkGray);
  const mgText = 'Maria Garcia';
  const mgW = doc.getTextWidth(mgText);
  doc.text(mgText, headerBoxX + (halfBoxW - mgW) / 2, y + 4);
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(5.5);
  doc.setTextColor(COLORS.mediumGray);
  const npText = 'Natural Person';
  const npW = doc.getTextWidth(npText);
  doc.text(npText, headerBoxX + (halfBoxW - npW) / 2, y + 7);
  doc.setFillColor(CORP_NATURAL);
  const badgeW = 18;
  const badgeH = 4;
  doc.roundedRect(headerBoxX + (halfBoxW - badgeW) / 2, y + boxH - 1, badgeW, badgeH, 1, 1, 'F');
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(5);
  doc.setTextColor(COLORS.white);
  const d60 = '60% Direct';
  const d60W = doc.getTextWidth(d60);
  doc.text(d60, headerBoxX + (halfBoxW - d60W) / 2, y + boxH + 2);

  const smithBoxX = headerBoxX + halfBoxW + boxGap;
  doc.setFillColor(COLORS.white);
  doc.setDrawColor(CORP_ENTITY);
  doc.setLineWidth(0.8);
  doc.roundedRect(smithBoxX, y, halfBoxW, boxH + 3, 1.5, 1.5, 'FD');
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(6.5);
  doc.setTextColor(COLORS.darkGray);
  const shText = 'Smith Holdings';
  const shW = doc.getTextWidth(shText);
  doc.text(shText, smithBoxX + (halfBoxW - shW) / 2, y + 4);
  doc.setFont('helvetica', 'normal');
  doc.setFontSize(5.5);
  doc.setTextColor(COLORS.mediumGray);
  const eoText = 'Entity Owner';
  const eoW = doc.getTextWidth(eoText);
  doc.text(eoText, smithBoxX + (halfBoxW - eoW) / 2, y + 7);
  doc.setFillColor(CORP_ENTITY);
  doc.roundedRect(smithBoxX + (halfBoxW - badgeW) / 2, y + boxH - 1, badgeW, badgeH, 1, 1, 'F');
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(5);
  doc.setTextColor(COLORS.white);
  const d40 = '40% Direct';
  const d40W = doc.getTextWidth(d40);
  doc.text(d40, smithBoxX + (halfBoxW - d40W) / 2, y + boxH + 2);

  y += boxH + 3 + boxGap + 1;

  doc.setFont('helvetica', 'italic');
  doc.setFontSize(6);
  doc.setTextColor('#00205b');
  doc.text('Drill down required: Who are the people behind Smith Holdings?', MARGIN.left + 4, y);
  y += 4;

  const drillPeople = [
    { name: 'John Smith', pct: '75% of Entity' },
    { name: 'Jane Smith', pct: '25% of Entity' },
  ];

  for (let dp = 0; dp < drillPeople.length; dp++) {
    const person = drillPeople[dp];
    const dpX = headerBoxX + dp * (halfBoxW + boxGap);
    doc.setFillColor(COLORS.white);
    doc.setDrawColor(CORP_NATURAL);
    doc.setLineWidth(0.8);
    doc.roundedRect(dpX, y, halfBoxW, boxH + 3, 1.5, 1.5, 'FD');
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(6.5);
    doc.setTextColor(COLORS.darkGray);
    const pnW = doc.getTextWidth(person.name);
    doc.text(person.name, dpX + (halfBoxW - pnW) / 2, y + 4);
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(5.5);
    doc.setTextColor(COLORS.mediumGray);
    const npW2 = doc.getTextWidth('Natural Person');
    doc.text('Natural Person', dpX + (halfBoxW - npW2) / 2, y + 7);
    doc.setFillColor(CORP_NATURAL);
    doc.roundedRect(dpX + (halfBoxW - badgeW) / 2, y + boxH - 1, badgeW, badgeH, 1, 1, 'F');
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(5);
    doc.setTextColor(COLORS.white);
    const pctW = doc.getTextWidth(person.pct);
    doc.text(person.pct, dpX + (halfBoxW - pctW) / 2, y + boxH + 2);
  }

  y += boxH + 3 + boxGap;

  doc.setDrawColor(COLORS.borderGray);
  doc.setLineWidth(0.3);
  doc.line(MARGIN.left + 4, y, MARGIN.left + leftColW - 4, y);
  y += 3;

  doc.setFont('helvetica', 'normal');
  doc.setFontSize(6);
  doc.setTextColor(COLORS.darkGray);
  doc.text('John Smith:', MARGIN.left + 4, y);
  doc.setFont('helvetica', 'bold');
  doc.text('40% \u00D7 75% = 30%', MARGIN.left + 24, y);
  doc.setFont('helvetica', 'normal');
  doc.text('Jane Smith:', MARGIN.left + leftColW / 2 + 2, y);
  doc.setFont('helvetica', 'bold');
  doc.text('40% \u00D7 25% = 10%', MARGIN.left + leftColW / 2 + 22, y);
  y += 4;

  const legendY = y;
