function buildProjectInformationDoc(doc: jsPDF, data: any): void {
  const po = data?.projectOverview || {};
  const seller = data?.sellerInfo || {};
  const footerText = 'T Bank - SBA Lending Division | Project Information Form';

  doc.addPage();
  let y = drawDocHeader(doc, 'Project Information');

  y = drawSectionHeader(doc, 'Project Team', y);

  y = drawFieldRow(doc, [
    { label: 'Project Name', fieldName: 'po_projectName', value: str(po.projectName) },
    { label: 'Referral Source', fieldName: 'po_referralSource', value: str(po.referralSource) },
  ], y);
  y += FIELD_SPACING;

  y = drawFieldRow(doc, [
    { label: 'BDO 1', fieldName: 'po_bdo1', value: str(po.bdo1) },
    { label: 'BDO 2', fieldName: 'po_bdo2', value: str(po.bdo2) },
    { label: 'BDA', fieldName: 'po_bda', value: str(po.bda) },
  ], y);
  y += FIELD_SPACING + 2;

  y = drawSectionHeader(doc, 'Industry & Classification', y);

  y = drawFieldRow(doc, [
    { label: 'Industry', fieldName: 'po_industry', value: str(po.industry) },
    { label: 'NAICS Code', fieldName: 'po_naicsCode', value: str(po.naicsCode) },
  ], y);
  y += FIELD_SPACING + 2;

  y = drawSectionHeader(doc, 'Project Purpose', y);

  y = drawFieldRow(doc, [
    { label: 'Primary Purpose', fieldName: 'po_primaryProjectPurpose', value: str(po.primaryProjectPurpose) },
  ], y);
  y += FIELD_SPACING;

  const secondary = (po.secondaryProjectPurposes || []).join(', ');
  y = drawFieldRow(doc, [
    { label: 'Secondary Purposes', fieldName: 'po_secondaryPurposes', value: secondary },
  ], y);
  y += FIELD_SPACING + 2;

  y = drawSectionHeader(doc, 'Project Description', y);

  drawLabel(doc, 'Project Description', MARGIN.left, y);
  y += 3;
  addTextArea(doc, 'po_projectDescription', MARGIN.left, y, CONTENT_W, MULTILINE_H, str(po.projectDescription));
  y += MULTILINE_H + 4;

  const isAcquisition = str(po.primaryProjectPurpose).includes('Acquisition') || str(po.primaryProjectPurpose).includes('Change of Ownership');
  if (isAcquisition) {
    if (needNewPage(y, 50)) {
      drawFooter(doc, footerText);
      doc.addPage();
      y = drawDocHeader(doc, 'Project Information');
    }

    y = drawSectionHeader(doc, 'Seller Information', y);

    y = drawFieldRow(doc, [
      { label: 'Seller Legal Name', fieldName: 'si_legalName', value: str(seller.legalName) },
      { label: 'Seller DBA Name', fieldName: 'si_dbaName', value: str(seller.dbaName) },
    ], y);
    y += FIELD_SPACING;

    y = drawFieldRow(doc, [
      { label: 'Contact Name', fieldName: 'si_contactName', value: str(seller.contactName) },
      { label: 'Phone', fieldName: 'si_phone', value: str(seller.phone) },
      { label: 'Email', fieldName: 'si_email', value: str(seller.email) },
    ], y);
    y += FIELD_SPACING;

    y = drawFieldRow(doc, [
      { label: 'Website', fieldName: 'si_website', value: str(seller.website) },
    ], y);
    y += FIELD_SPACING;

    y = drawFieldRow(doc, [
      { label: 'Type of Acquisition', fieldName: 'si_typeOfAcquisition', value: str(seller.typeOfAcquisition), type: 'combo',
        options: ['', 'stock', 'asset'] },
      { label: 'Purchasing 100%?', fieldName: 'si_purchasing100Percent', value: str(seller.purchasing100Percent), type: 'combo',
        options: ['', 'yes', 'no'] },
    ], y);
    y += FIELD_SPACING;

    y = drawFieldRow(doc, [
      { label: 'Contract Status', fieldName: 'si_purchaseContractStatus', value: str(seller.purchaseContractStatus), type: 'combo',
        options: ['', 'no_contract', 'loi_signed', 'contract_drafted', 'fully_executed'] },
      { label: 'Seller Carry Note?', fieldName: 'si_hasSellerCarryNote', value: str(seller.hasSellerCarryNote), type: 'combo',
        options: ['', 'yes', 'no'] },
    ], y);
    y += FIELD_SPACING;

    if (needNewPage(y, MULTILINE_H + 6)) {
      drawFooter(doc, footerText);
      doc.addPage();
      y = drawDocHeader(doc, 'Project Information');
    }

    drawLabel(doc, 'Business Description', MARGIN.left, y);
    y += 3;
    addTextArea(doc, 'si_businessDescription', MARGIN.left, y, CONTENT_W, MULTILINE_H, str(seller.businessDescription));
    y += MULTILINE_H + 3;
  }

  drawFooter(doc, footerText);
}

function buildQuestionnaireDoc(doc: jsPDF, data: any, rules: any[], responses: any[]): void {
  const po = data?.projectOverview || {};
  const allPurposes = [po.primaryProjectPurpose, ...(po.secondaryProjectPurposes || [])].filter(Boolean);
  const footerText = 'T Bank - SBA Lending Division | Business Questionnaire';
  const deletedRuleIds = data?.questionnaireDeletedRuleIds || [];

  const filteredRules = (rules || []).filter((rule: any) => {
    if (!rule.enabled) return false;
    if (deletedRuleIds.includes(rule.id)) return false;
    const ruleExclude = rule.excludePurposes || [];
    if (ruleExclude.length > 0 && purposeExcluded(ruleExclude, allPurposes)) return false;
    if (rule.alwaysShow) return true;
    const cat = rule.mainCategory || rule.category;
    if (cat === 'Business Overview') return true;
    if (cat === 'Project Purpose') {
      const keys = rule.purposeKeys && rule.purposeKeys.length > 0 ? rule.purposeKeys : (rule.purposeKey ? [rule.purposeKey] : []);
      if (keys.length === 0) return true;
      return keys.some((k: string) => purposeKeyMatches(k, allPurposes));
    }
    if (cat === 'Industry') {
      const codes = rule.naicsCodes || rule.naics_codes || [];
      if (codes.length === 0) return false;
      const projectNaics = po.naicsCode || '';
      if (!projectNaics || projectNaics.trim() === '') return false;
      return codes.some((code: string) => {
        if (!code || code.trim() === '') return false;
        return projectNaics.startsWith(code) || code.startsWith(projectNaics);
      });
    }
    return false;
  }).sort((a: any, b: any) => (a.questionOrder || a.order || 0) - (b.questionOrder || b.order || 0));

  const responseMap = new Map<string, string>();
  for (const r of responses) {
    const raw = r.content || '';
    const cleaned = raw
      .replace(/<br\s*\/?>/gi, '\n')
      .replace(/<\/p>/gi, '\n')
      .replace(/<\/div>/gi, '\n')
      .replace(/<\/li>/gi, '\n')
      .replace(/<[^>]*>/g, '')
      .replace(/&nbsp;/g, ' ')
      .replace(/&amp;/g, '&')
      .replace(/&lt;/g, '<')
      .replace(/&gt;/g, '>')
      .replace(/&quot;/g, '"')
      .replace(/&#39;/g, "'")
      .replace(/\n\s*\n/g, '\n')
      .trim();
    responseMap.set(String(r.ruleId), cleaned);
  }

  doc.addPage();
  let y = drawDocHeader(doc, 'Business Questionnaire');

  if (filteredRules.length === 0) {
    doc.setFont('helvetica', 'normal');
    doc.setFontSize(LABEL_SIZE);
    doc.setTextColor(COLORS.lightGray);
    doc.text('No questionnaire questions configured for this project.', MARGIN.left, y);
    drawFooter(doc, footerText);
    return;
  }

  const grouped: Record<string, any[]> = {};
  for (const rule of filteredRules) {
    const cat = rule.mainCategory || rule.category || 'Business Overview';
    if (!grouped[cat]) grouped[cat] = [];
    grouped[cat].push(rule);
  }

  const primaryPurpose = po.primaryProjectPurpose || '';
  const secondaryPurposes = po.secondaryProjectPurposes || [];
  const purposeBlocks = groupRulesByPurpose(
    grouped['Project Purpose'] || [],
    primaryPurpose,
    Array.isArray(secondaryPurposes) ? secondaryPurposes : []
  );

  let qIndex = 0;

  function drawQuestion(rule: any) {
    const totalNeeded = QUESTIONNAIRE_H + 20;
    if (needNewPage(y, totalNeeded)) {
      drawFooter(doc, footerText);
      doc.addPage();
      y = drawDocHeader(doc, 'Business Questionnaire');
    }

    const answer = responseMap.get(String(rule.id)) || '';
    const qText = rule.questionText || '';

    doc.setFont('helvetica', 'normal');
    doc.setFontSize(LABEL_SIZE);
    doc.setTextColor(COLORS.darkGray);
    const lines = doc.splitTextToSize(`${qIndex + 1}. ${qText}`, CONTENT_W);
    for (const line of lines) {
      doc.text(line, MARGIN.left, y);
      y += 4;
    }
    y += 2;

    const fieldName = `q_${rule.id}`;
    registerField(fieldName, 'questionnaireResponses', String(rule.id), 'text');
    addTextArea(doc, fieldName, MARGIN.left, y, CONTENT_W, QUESTIONNAIRE_H, answer);
    y += QUESTIONNAIRE_H + 4;
    qIndex++;
  }

  const categoryOrder = ['Business Overview', 'Project Purpose', 'Industry'];
  for (const category of categoryOrder) {
    const categoryRules = grouped[category];
    if (!categoryRules || categoryRules.length === 0) continue;

    if (needNewPage(y, SECTION_GAP + QUESTIONNAIRE_H + 20)) {
      drawFooter(doc, footerText);
      doc.addPage();
      y = drawDocHeader(doc, 'Business Questionnaire');
    }

    y = drawSectionHeader(doc, category, y);

    if (category === 'Project Purpose') {
      for (const block of purposeBlocks) {
        if (block.purposeName) {
          if (needNewPage(y, SUB_GAP + QUESTIONNAIRE_H + 20)) {
            drawFooter(doc, footerText);
            doc.addPage();
            y = drawDocHeader(doc, 'Business Questionnaire');
          }
          y = drawSubHeader(doc, block.purposeName, y);
        }
        for (const rule of block.rules) {
          drawQuestion(rule);
        }
      }
    } else {
      for (const rule of categoryRules) {
        drawQuestion(rule);
      }
    }
  }

  drawFooter(doc, footerText);
}

export async function generateFillableEnvelopePDF(
  project: Project,
  docIndex?: number,
  questionnaireRules?: any[],
  questionnaireResponses?: any[],
  docIndices?: number[]
): Promise<Uint8Array> {
  const doc = new jsPDF({ unit: 'mm', format: 'letter' });
  const data = project.data as any;

  const builders = [
    () => buildBusinessApplicantDoc(doc, data),
    () => buildIndividualApplicantDoc(doc, data),
    () => buildProjectInformationDoc(doc, data),
    () => buildQuestionnaireDoc(doc, data, questionnaireRules || [], questionnaireResponses || []),
  ];

  if (docIndices && docIndices.length > 0) {
    let first = true;
    for (const idx of docIndices) {
      if (idx >= 0 && idx < 4) {
        if (first && idx === 0) {
          buildBusinessApplicantDoc(doc, data);
          first = false;
        } else if (first) {
          doc.deletePage(1);
          builders[idx]();
          first = false;
        } else {
          builders[idx]();
        }
      }
    }
  } else if (docIndex !== undefined && docIndex >= 0 && docIndex < 4) {
    if (docIndex === 0) {
      buildBusinessApplicantDoc(doc, data);
    } else {
      doc.deletePage(1);
      builders[docIndex]();
    }
  } else {
    buildBusinessApplicantDoc(doc, data);
    builders[1]();
    builders[2]();
    builders[3]();
  }

  const arrayBuffer = doc.output('arraybuffer');
  return new Uint8Array(arrayBuffer);
}

export async function extractEnvelopePdfFields(pdfBuffer: Buffer): Promise<Record<string, any>> {
  const pdfDoc = await PDFDocument.load(pdfBuffer);
  const form = pdfDoc.getForm();
  const fields = form.getFields();
  const extracted: Record<string, any> = {};

  for (const field of fields) {
    const name = field.getName();
    try {
      if ('getSelected' in field && typeof (field as any).getSelected === 'function') {
        const selected = (field as any).getSelected();
        extracted[name] = Array.isArray(selected) ? (selected.length > 0 ? selected[0] : '') : (selected || '');
      } else if ('isChecked' in field && typeof (field as any).isChecked === 'function') {
        extracted[name] = (field as any).isChecked();
      } else if ('getText' in field && typeof (field as any).getText === 'function') {
        extracted[name] = (field as any).getText() || '';
      }
    } catch {
      extracted[name] = '';
    }
  }

  return extracted;
}

export function remapIndividualApplicantFields(
  extractedFields: Record<string, any>,
  targetIndex: number
): Record<string, any> {
  const remapped: Record<string, any> = {};
  for (const [key, value] of Object.entries(extractedFields)) {
    if (key.startsWith('ia0_')) {
      const suffix = key.slice(4);
      remapped[`ia${targetIndex}_${suffix}`] = value;
    } else if (key.startsWith('oob0_')) {
      const suffix = key.slice(5);
      remapped[`oob${targetIndex}_${suffix}`] = value;
    }
  }
  return remapped;
}

export function remapPfsFieldsForApplicant(
  extractedFields: Record<string, any>,
  sourceIndex: number,
  targetIndex: number
): Record<string, any> {
  const remapped: Record<string, any> = {};
  const srcPrefix = `ia${sourceIndex}_pfs_`;
  const tgtPrefix = `ia${targetIndex}_pfs_`;
  for (const [key, value] of Object.entries(extractedFields)) {
    if (key.startsWith(srcPrefix)) {
      const suffix = key.slice(srcPrefix.length);
      remapped[`${tgtPrefix}${suffix}`] = value;
    }
  }
  return remapped;
}

export function applyEnvelopeFieldsToData(
  existingData: any,
  extractedFields: Record<string, any>
): any {
  const data = JSON.parse(JSON.stringify(existingData || {}));

  const oobFlat: Record<string, any> = {};

  for (const [fieldName, value] of Object.entries(extractedFields)) {
    if (value === '' || value === null || value === undefined) continue;

    const mapping = ENVELOPE_FIELD_MAP[fieldName];
    if (!mapping) continue;

    const { section, path: fieldPath, type } = mapping;

    if (section === 'questionnaireResponses') continue;

    let processedValue: any = value;
    if (type === 'boolean') {
      processedValue = !!value;
    }

    if (type === 'yesno_yes') {
      if (value === true || value === 'On') {
        processedValue = 'Yes';
      } else {
        continue;
      }
    }

    if (type === 'yesno_no') {
      if (value === true || value === 'On') {
        processedValue = 'No';
      } else {
        continue;
      }
    }

    if (fieldName === 'ba_entityType' && typeof processedValue === 'string') {
      const entityTypeMap: Record<string, string> = {
        'Cooperative': 'cooperative',
        'Corporation': 'corporation',
        'Limited Liability Company (LLC)': 'llc',
        'Limited Liability Partnership': 'llp',
        'Partnership': 'partnership',
        'Sole Proprietorship': 'sole-proprietor',
        'Subchapter S Corporation': 's-corp',
        'Trust': 'trust',
      };
      processedValue = entityTypeMap[processedValue] || processedValue;
    }

    if (fieldName.endsWith('_projectRole') && typeof processedValue === 'string') {
      processedValue = reverseProjectRoleMap[processedValue] || processedValue;
    }

    if (fieldName.endsWith('_ownershipType') && typeof processedValue === 'string') {
      processedValue = reverseOwnershipTypeMap[processedValue] || processedValue;
    }

    if (fieldName.endsWith('_businessRole') && typeof processedValue === 'string') {
      processedValue = reverseBusinessRoleMap[processedValue] || processedValue;
    }

    if (fieldName === 'po_secondaryPurposes' && typeof processedValue === 'string') {
      processedValue = processedValue.split(',').map((s: string) => s.trim()).filter(Boolean);
    }

    if ((fieldName.endsWith('_dateOfQuotation') || fieldName.endsWith('_datePurchased') || fieldName.endsWith('_dateOfBirth')) && typeof processedValue === 'string') {
      const match = processedValue.trim().match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
      if (match) {
        const month = match[1].padStart(2, '0');
        const day = match[2].padStart(2, '0');
        processedValue = `${match[3]}-${month}-${day}`;
      }
    }

    if (section === 'otherOwnedBusinesses') {
      oobFlat[fieldPath] = processedValue;
      continue;
    }

    if (section === 'personalFinancialStatements') {
      if (!data.personalFinancialStatements) data.personalFinancialStatements = {};
      const pfsParts = fieldPath.split('.');
      const appIdx = parseInt(pfsParts[0]);
      const applicant = data.individualApplicants?.[appIdx];
      const applicantId = applicant?.id || `applicant-${appIdx + 1}`;
      if (!data.personalFinancialStatements[applicantId]) data.personalFinancialStatements[applicantId] = {};
      const pfsObj = data.personalFinancialStatements[applicantId];
      const subParts = pfsParts.slice(1);

      if (subParts.length === 1) {
        pfsObj[subParts[0]] = processedValue;
      } else if (subParts.length === 3) {
        const arrayField = subParts[0];
        const arrIdx = parseInt(subParts[1]);
        const prop = subParts[2];
        if (!Array.isArray(pfsObj[arrayField])) pfsObj[arrayField] = [];
        while (pfsObj[arrayField].length <= arrIdx) pfsObj[arrayField].push({});
        pfsObj[arrayField][arrIdx][prop] = processedValue;
      }
      continue;
    }

    if (!data[section]) data[section] = {};

    const parts = fieldPath.split('.');
    let target = data[section];

    if (section === 'individualApplicants') {
      if (!Array.isArray(data.individualApplicants)) data.individualApplicants = [{}];
      const idx = parseInt(parts[0]);
      while (data.individualApplicants.length <= idx) {
        data.individualApplicants.push({ id: `imported-${Date.now()}-${data.individualApplicants.length}` });
      }
      if (!data.individualApplicants[idx].id) {
        data.individualApplicants[idx].id = `imported-${Date.now()}-${idx}`;
      }
      target = data.individualApplicants[idx];
      const subParts = parts.slice(1);
      for (let i = 0; i < subParts.length - 1; i++) {
        if (!target[subParts[i]]) target[subParts[i]] = {};
        target = target[subParts[i]];
      }
      target[subParts[subParts.length - 1]] = processedValue;
      continue;
    }

    for (let i = 0; i < parts.length - 1; i++) {
      if (!target[parts[i]]) target[parts[i]] = {};
      target = target[parts[i]];
    }
    target[parts[parts.length - 1]] = processedValue;
  }

  if (Object.keys(oobFlat).length > 0) {
    if (!data.otherOwnedBusinesses) data.otherOwnedBusinesses = {};

    if (oobFlat.hasOtherBusinesses) {
      data.otherOwnedBusinesses.hasOtherBusinesses = oobFlat.hasOtherBusinesses;
    }

    const businesses: any[] = data.otherOwnedBusinesses.businesses || [];

    for (let appIdx = 0; appIdx < 5; appIdx++) {
      const appHasKey = `applicant_${appIdx}_hasOtherBusinesses`;
      if (oobFlat[appHasKey]) {
        const hasOtherVal = oobFlat[appHasKey];
        if (hasOtherVal === 'Yes' || hasOtherVal === 'yes') {
          data.otherOwnedBusinesses.hasOtherBusinesses = 'Yes';
        }
      }

      for (let bizIdx = 0; bizIdx < 10; bizIdx++) {
        const bizPrefix = `applicant_${appIdx}_biz_${bizIdx}_`;
        const bizName = oobFlat[`${bizPrefix}businessName`];
        if (!bizName) continue;

        const applicant = data.individualApplicants?.[appIdx];
        const ownerName = oobFlat[`${bizPrefix}ownerName`] ||
          (applicant ? `${applicant.firstName || ''} ${applicant.lastName || ''}`.trim() : '');
        const pctStr = oobFlat[`${bizPrefix}ownershipPct`] || '';
        const pctNum = pctStr ? parseFloat(String(pctStr).replace(/[%\s]/g, '')) : 0;
        const corpGuarantor = oobFlat[`${bizPrefix}corporateGuarantor`];

        businesses.push({
          id: `imported-oob-${Date.now()}-${appIdx}-${bizIdx}`,
          businessName: bizName,
          industry: oobFlat[`${bizPrefix}industry`] || '',
          corporateGuarantor: corpGuarantor === 'Yes' || corpGuarantor === 'yes',
          ownershipPercentages: [{
            ownerName,
            percentage: isNaN(pctNum) ? 0 : pctNum,
            roleInBusiness: oobFlat[`${bizPrefix}roleInBusiness`] || '',
          }],
        });
      }
    }

    data.otherOwnedBusinesses.businesses = businesses;
  }

  return data;
}

export function extractQuestionnaireResponses(
  extractedFields: Record<string, any>
): Array<{ ruleId: string; content: string }> {
  const responses: Array<{ ruleId: string; content: string }> = [];
  for (const [fieldName, value] of Object.entries(extractedFields)) {
    if (!fieldName.startsWith('q_') || !value) continue;
    const ruleId = fieldName.replace('q_', '');
    responses.push({ ruleId, content: String(value) });
  }
  return responses;
}
